	}
	if cmd.Amount <= 0 {
		fields = append(fields, httpx.FieldError{Field: "amount", Code: "must_be_positive"})
	}
	if cmd.IdempotencyKey == "" {
		fields = append(fields, httpx.FieldError{Field: "idempotency_key", Code: "required"})
