	defer rows.Close()

	var result []domain.Entitlement
	for rows.Next() {
		var e domain.Entitlement
		if err := rows.Scan(&e.OfferingID, &e.OfferingName, &e.TransactionID, &e.GrantedAt); err != nil {
			return nil, fmt.Errorf("scan entitlement: %w", err)
		}
		result = append(result, e)
