		p.mu.Lock()
		p.cache[transactionID] = result
		p.mu.Unlock()
		return &processdeposit.ChargeResult{
			Success:     result.Success,
			ProviderRef: result.ProviderRef,
			Reason:      result.Reason,
		}, nil
	case <-ctx.Done():
		return nil, ctx.Err()
	}
}

